<template>
  <v-container class="py-8">
    <v-btn text class="text-none font-weight-bold mb-4" color="primary" :to="servicesLink">
      <v-icon left small>arrow_back</v-icon>
      Back to services
    </v-btn>

    <h1 class="text-h4 font-weight-bold mb-2">Book</h1>
    <div class="text-body-2 text--secondary mb-6">Choose a date and time slot, then enter your details.</div>

    <v-alert v-if="error" type="error" outlined class="rounded-lg mb-6">{{ error }}</v-alert>

    <v-card outlined class="rounded-xl pa-4 pa-md-6 mb-6">
      <v-row>
        <v-col cols="12" md="4">
          <v-text-field
            v-model="date"
            label="Date"
            type="date"
            outlined
            dense
            :disabled="loadingSlots"
            @change="loadSlots"
          />
        </v-col>
        <v-col cols="12" md="8">
          <div class="text-body-2 text--secondary mb-2">Available time slots</div>
          <div v-if="loadingSlots" class="py-6 text-center">
            <v-progress-circular indeterminate color="primary" />
          </div>
          <div v-else class="d-flex flex-wrap">
            <v-btn
              v-for="s in slots"
              :key="s.startAt"
              class="mr-2 mb-2 text-none"
              :color="selectedStartAt === s.startAt ? 'primary' : 'grey lighten-3'"
              :dark="selectedStartAt === s.startAt"
              @click="selectSlot(s)"
            >
              {{ formatTime(s.startAt) }}
            </v-btn>
            <div v-if="!slots.length" class="text-body-2 text--secondary py-3">No slots available.</div>
          </div>
        </v-col>
      </v-row>
    </v-card>

    <v-card outlined class="rounded-xl pa-4 pa-md-6">
      <v-row>
        <v-col cols="12" md="4">
          <v-text-field v-model="customerName" label="Full name" outlined dense />
        </v-col>
        <v-col cols="12" md="4">
          <v-text-field v-model="customerPhone" label="Phone" outlined dense />
        </v-col>
        <v-col cols="12" md="4">
          <v-text-field v-model="customerEmail" label="Email" outlined dense />
        </v-col>
      </v-row>
      <div class="d-flex align-center">
        <v-spacer />
        <v-btn
          color="primary"
          class="text-none font-weight-bold"
          :loading="submitting"
          :disabled="!canSubmit"
          @click="submit"
        >
          Confirm booking
        </v-btn>
      </div>

      <v-alert v-if="successBookingId" type="success" outlined class="rounded-lg mt-4">
        Booking created. Reference: <strong>{{ successBookingId }}</strong>
      </v-alert>
    </v-card>
  </v-container>
</template>

<script>
import { createSalonBooking, fetchSalonAvailability } from '@/services/salonPublic'

export default {
  name: 'SalonBookView',
  data() {
    const today = new Date()
    const pad = (n) => String(n).padStart(2, '0')
    const yyyyMmDd = `${today.getFullYear()}-${pad(today.getMonth() + 1)}-${pad(today.getDate())}`
    return {
      date: yyyyMmDd,
      slots: [],
      loadingSlots: true,
      selectedStartAt: '',
      customerName: '',
      customerPhone: '',
      customerEmail: '',
      submitting: false,
      error: '',
      successBookingId: ''
    }
  },
  computed: {
    merchantSlug() {
      return String(this.$route.params.merchantSlug || '').trim()
    },
    serviceId() {
      return String(this.$route.params.serviceId || '').trim()
    },
    servicesLink() {
      return `/m/${encodeURIComponent(this.merchantSlug)}/salon/services`
    },
    canSubmit() {
      return (
        !this.submitting &&
        this.selectedStartAt &&
        String(this.customerName).trim().length >= 2 &&
        String(this.customerPhone).trim().length >= 7 &&
        String(this.customerEmail).trim().length >= 5
      )
    }
  },
  async created() {
    await this.loadSlots()
  },
  methods: {
    async loadSlots() {
      this.loadingSlots = true
      this.error = ''
      this.successBookingId = ''
      this.selectedStartAt = ''
      try {
        this.slots = await fetchSalonAvailability(this.merchantSlug, this.serviceId, this.date)
      } catch (e) {
        this.error = e && e.message ? e.message : 'Could not load slots.'
        this.slots = []
      } finally {
        this.loadingSlots = false
      }
    },
    selectSlot(slot) {
      this.selectedStartAt = slot.startAt
    },
    formatTime(iso) {
      try {
        const d = new Date(iso)
        return d.toLocaleTimeString(undefined, { hour: '2-digit', minute: '2-digit' })
      } catch {
        return String(iso)
      }
    },
    async submit() {
      if (!this.canSubmit) return
      this.submitting = true
      this.error = ''
      this.successBookingId = ''
      try {
        const bookingId = await createSalonBooking(this.merchantSlug, {
          serviceId: this.serviceId,
          startAt: this.selectedStartAt,
          customerName: this.customerName,
          customerPhone: this.customerPhone,
          customerEmail: this.customerEmail
        })
        this.successBookingId = bookingId
      } catch (e) {
        this.error = e && e.message ? e.message : 'Could not create booking.'
      } finally {
        this.submitting = false
      }
    }
  }
}
</script>

